import pytest
import requests

def test_unauthenticated_request_denied_audit_logs(
    fhir_base_url,
    org_a_id,
):
    resp = requests.get(
        f"{fhir_base_url}/AuditEvent",
        params={"agent-organization": org_a_id},
    )
    assert resp.status_code == 401, (
        f"Expected 401 for unauthenticated request, got {resp.status_code}"
    )
    has_www_auth = "WWW-Authenticate" in resp.headers
    body = resp.json() if resp.content else {}
    has_outcome = body.get("resourceType") == "OperationOutcome"
    assert has_www_auth or has_outcome, (
        "Expected WWW-Authenticate header or OperationOutcome body on 401"
    )
